data "aws_region" "current" {}

resource "aws_s3_bucket" "app" {
  for_each = toset(["logs", "backups", "artifacts"])
  bucket   = "myapp-${each.key}-${data.aws_region.current.name}"

  tags = {
    Name      = each.key
    ManagedBy = "Terraform"
  }
}

output "bucket_arns" {
  value       = { for k, v in aws_s3_bucket.app : k => v.arn }
  description = "Map of bucket purpose to ARN"
}
